export const About = () => {
	return (
		<div className="about">
			<div className="about-content">
				<h1>What is SpotifyMe?</h1>
                <p>
                    SpotifyMe was inspired by that one thing we all wait for towards the end of the year, <strong>Spotify Wrapped</strong>! 
                    Aren't we curious as to how our music tastes and genre changes through the weeks, months, and even throughout the years? 
                    I know I am. I wanted to make this web application as simple to use as possible, so for now, you are able to do the 
                    following: select which time frames you would like to view 
                </p>
			</div>
		</div>
	);
};
